sp_rectangle_menu_item.record_script:
//AA -STRY0033865
//KT - STRY0033865 Fix from AGO to AHEAD

var isGTA = gs.getUser().hasRole("x_153465_discovert.tasker_global_Tasking_Authority_member_admin");

var assignedMembers ="^assigned_toIN";

// Menu Item Label
var label = 'Acceptance Overdue';

// Read application property
var daysBeforeTaskAcceptanceIsOverdue = gs.getProperty("x_153465_discovert.#DaysBeforeTaskAcceptanceIsOverdue");

// maximum number of entries in this Menu
var max = 5;
var filter = 'state=1';

var t = data;  // shortcut
t.items = [];

var u = gs.getUser().getID();
// use record watchers to tell header when to update dropdown counts
t.record_watchers = [];

//HT - STRY0058891
//gs.info("record watching" + t.record_watchers);
t.record_watchers.push({'table':'x_153465_discovert_route_task_instance','filter':filter});

//KTORRES: BASED ON PRIMARY ASSIGNEE TA
//------------------------------------------------------------------------------------------------------------------
var primary_assigneeFilter = "primary_assigneeIN";
var grPrimaryAssigneeTA = new GlideRecord('x_153465_discovert_discover_office_members');
grPrimaryAssigneeTA.addQuery('office_task_authority', 'true');
grPrimaryAssigneeTA.addEncodedQuery('office_memberDYNAMIC90d1921e5f510100a9ad2572f2b477fe');
grPrimaryAssigneeTA.orderByDesc('sys_updated_on');
grPrimaryAssigneeTA.query();

var memberOUs = [];

while (grPrimaryAssigneeTA.next()) {
  memberOUs.push(grPrimaryAssigneeTA.getValue('discover_office_hierarchy'));
}

primary_assigneeFilter+= memberOUs.toString();


//------------------------------------------------------------------------------------------------------------------

//count via aggregate

if(isGTA)
  primary_assigneeFilter += "^ORprimary_assignee.tasking_authoritiesISEMPTY"

var a = new GlideAggregate('x_153465_discovert_route_task_instance');
a.addEncodedQuery(filter);
//a.addEncodedQuery('assigned_toDYNAMIC90d1921e5f510100a9ad2572f2b477fe');
a.addEncodedQuery(primary_assigneeFilter);
a.addEncodedQuery('suspense_dateRELATIVELE@dayofweek@ahead@'+daysBeforeTaskAcceptanceIsOverdue);
a.addAggregate("COUNT");
a.query();

var totcount=0;
if(a.next()){
totcount = a.getAggregate("COUNT");
}

var z = new GlideRecord('x_153465_discovert_route_task_instance');
z.addEncodedQuery(filter);
z.addEncodedQuery(primary_assigneeFilter);
z.addEncodedQuery('suspense_dateRELATIVELE@dayofweek@ahead@'+daysBeforeTaskAcceptanceIsOverdue);
z.orderByDesc('sys_updated_on');
z.setLimit(max);
z.query();

while (z.next()) {  
   t.items.push({
    title: z.getValue('task_name') ,
    type: 'link',
    href: '?sys_id='+ z.getValue('sys_id') + '&view=sp&id=discovertasker_taskdetails&table=x_153465_discovert_route_task_instance'
  }); 

  if (!z.canRead()){
    continue;
  }
  var a = {};
  if (z.short_description.nil()){
    a.short_description = "(No description)";
  }
  a.__table = z.getTableName();
  a.type = 'record';
}


t.items.sort(function(a, b) {
  return b.sortOrder - a.sortOrder;
});

t.items = t.items.slice(0, 5); 

t.count = totcount;



//var link = {title: gs.getMessage('View all requests'), type: 'link', href: '?id=discovertasker_detailsdrilldown&view=Unassigned&table=x_153465_discovert_route_task_instance&filter='+primary_assigneeFilter+'%5EstateIN1%5Esuspense_date<javascript:gs.beginningOfNextWeek()', items: []};
var link = {
            title: gs.getMessage('View all requests'), 
            type: 'link', 
            href: '?id=discovertasker_detailsdrilldown&view=Unassigned&table=x_153465_discovert_route_task_instance&filter='+ filter+ '^'+primary_assigneeFilter+'^suspense_dateRELATIVELE@dayofweek@ahead@'+daysBeforeTaskAcceptanceIsOverdue +'&label='+label, 
            items: []                                                                                                               
           };
t.items.push(link); // put 'View all requests' first
